document.addEventListener("DOMContentLoaded",(()=>{document.querySelectorAll(".add-all-to-edit").forEach((element=>{if(element.checked===true){element.checked=false}}))}));let $selectAllToEdit=document.querySelector("#select-all-to-edit");let $addAllToDelete=document.querySelector("#add-all-to-delete");let $addAllToActive=document.querySelector("#add-all-to-active");$selectAllToEdit?.addEventListener("click",(function(){$selectAllToEdit.classList.toggle("selected");if($selectAllToEdit.classList.contains("selected")){$selectAllToEdit.innerText="Снять выбор";$selectAllToEdit.classList.remove("btn-outline-primary");$selectAllToEdit.classList.add("btn-primary")}else{$selectAllToEdit.innerText="Выбрать все";$selectAllToEdit.classList.add("btn-outline-primary");$selectAllToEdit.classList.remove("btn-primary")}const checkboxes=document.querySelectorAll(".add-all-to-edit");checkboxes.forEach((checkbox=>{checkbox.checked=$selectAllToEdit.classList.contains("selected")}));const atLeastOneChecked=Array.from(checkboxes).some((cb=>cb.checked));if(atLeastOneChecked){$addAllToDelete.classList.remove("d-none");$addAllToActive.classList.remove("d-none")}else{$addAllToDelete.classList.add("d-none");$addAllToActive.classList.add("d-none")}}));let $checkboxesAllToEdit=document.querySelectorAll(".add-all-to-edit");for($checkboxAllToEdit of $checkboxesAllToEdit){$checkboxAllToEdit?.addEventListener("click",(function(){const checkboxes=document.querySelectorAll(".add-all-to-edit");const atLeastOneChecked=Array.from(checkboxes).some((cb=>cb.checked));if(atLeastOneChecked){$addAllToDelete.classList.remove("d-none");$addAllToActive.classList.remove("d-none")}else{$addAllToDelete.classList.add("d-none");$addAllToActive.classList.add("d-none")}}))}